queries.item:
CREATE TABLE IF NOT EXISTS `?:sphinx_cache` (
    `cache_key`     VARCHAR(255) NOT NULL PRIMARY KEY,
    `cache_data`    LONGBLOB NOT NULL,
    `expires_at`    INT UNSIGNED NOT NULL COMMENT 'Unix timestamp',
    KEY `idx_expires` (`expires_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

ALTER TABLE `?:sphinx_destinations`
    ADD COLUMN IF NOT EXISTS `full_path` VARCHAR(500) DEFAULT NULL COMMENT 'Breadcrumb: City, Region, Country, Continent'
    AFTER `country_code`;
